def atbash(text):
    output = ""
    for char in text:
        val = ord(char)
        if 65 <= val <= 90: # A-Z
            output += chr(155 - val)
        elif 97 <= val <= 122: # a-z
            output += chr(219 - val)
        else:
            output += char
    return output

if __name__ == "__main__":
    print(f"'abc' -> {atbash('abc')}")
